diff --git a/llvm/include/llvm/Analysis/ScalarEvolution.h b/llvm/include/llvm/Analysis/ScalarEvolution.h
index a011f16b4d95..258b4757bbec 100644
--- a/llvm/include/llvm/Analysis/ScalarEvolution.h
+++ b/llvm/include/llvm/Analysis/ScalarEvolution.h
@@ -2289,6 +2289,8 @@ private:
                               SmallVectorImpl<const SCEV *> &NewOps);

   FoldingSet<SCEV> UniqueSCEVs;
+  /// A set of SCEV objects that are being processed by getRange.
+  SmallPtrSet<const SCEV *, 4> PendingRanges;
   FoldingSet<SCEVPredicate> UniquePreds;
   BumpPtrAllocator SCEVAllocator;

diff --git a/llvm/lib/Analysis/ScalarEvolution.cpp b/llvm/lib/Analysis/ScalarEvolution.cpp
index 7673c3548175..5ccbed037c0a 100644
--- a/llvm/lib/Analysis/ScalarEvolution.cpp
+++ b/llvm/lib/Analysis/ScalarEvolution.cpp
@@ -6654,6 +6654,9 @@ const ConstantRange &ScalarEvolution::getRangeRef(
   if (I != Cache.end())
     return I->second;

+
+
+
   if (const SCEVConstant *C = dyn_cast<SCEVConstant>(S))
     return setRange(C, SignHint, ConstantRange(C->getAPInt()));

@@ -7074,7 +7077,35 @@ ConstantRange ScalarEvolution::getRangeForAffineAR(const SCEV *Start,
 ConstantRange ScalarEvolution::getRangeForAffineNoSelfWrappingAR(
     const SCEVAddRecExpr *AddRec, const SCEV *MaxBECount, unsigned BitWidth,
     ScalarEvolution::RangeSignHint SignHint) {
+  struct ScopedGuard {
+    SmallPtrSet<const SCEV *, 4> &Set;
+    const SCEV *Val;
+    bool IsNew;
+    ScopedGuard(SmallPtrSet<const SCEV *, 4> &S, const SCEV *V)
+        : Set(S), Val(V) {
+      IsNew = Set.insert(Val).second;
+    }
+    ~ScopedGuard() {
+      if (IsNew)
+        Set.erase(Val);
+    }
+  };
+  ScopedGuard Guard(PendingRanges, AddRec);
+  if (!Guard.IsNew) {
+    auto GetRange = [&](const SCEV *S) {
+      return (SignHint == HINT_RANGE_SIGNED) ? getSignedRange(S)
+                                             : getUnsignedRange(S);
+    };
+    const ConstantRange &StartRange = GetRange(AddRec->getStart());
+    const SCEV *End = AddRec->evaluateAtIteration(MaxBECount, *this);
+    const ConstantRange &EndRange = GetRange(End);
+    return StartRange.unionWith(EndRange);
+  }
+
+
   assert(AddRec->isAffine() && "Non-affine AddRecs are not suppored!\n");
+
+
   assert(AddRec->hasNoSelfWrap() &&
          "This only works for non-self-wrapping AddRecs!");
   const bool IsSigned = SignHint == HINT_RANGE_SIGNED;

